ruleBookInfo.tocUrl:
@js:
let mid = String(result).match(/data-mid="(\d+)"/)[1];
java.put("mid", mid); // 压入内存，章节URL生成需要用到
"https://api-get-v3.mgsearcher.com/api/manga/get?mid=" + mid + "&mode=all";

ruleContent.content:
@js:
let json = JSON.parse(result);
let images = json.data.info.images.images; // 定位到 JSON 中的图片数组
let imgTags = [];

// 如果 JSON 没带域名前缀，包子漫画 V3 接口的默认主域名通常是下方这个
let host = json.data.info.domain || "https://f40-1-4.g-mh.online"; 

for (let i = 0; i < images.length; i++) {
    let imgUrl = images[i].url;
    // 有些接口返回的是绝对路径，有些是相对路径，要做个兼容判断
    if (!imgUrl.startsWith("http")) {
        imgUrl = host + imgUrl;
    }
    imgTags.push('<img src="' + imgUrl + '">');
}

// 用换行符拼接所有 img 标签，交给底层阅读引擎排版渲染
imgTags.join('\n');

ruleToc.chapterList:
@js:
let json = JSON.parse(result);
// 兼容多版本 API 字段格式
let list = json.data.chapters || json.data.info.chapters || [];
// 删掉了 .reverse()，不进行物理内存反转，直接遍历序列化
list.map(item => JSON.stringify(item));

ruleToc.chapterName:
@js: 
let obj = JSON.parse(result);
// 穷举常见的包子漫画键名。如果都不对，直接把这个对象的 JSON 源码打印成章节名！
obj.name || obj.title || obj.chapter_name || obj.chapter_title || (obj.attributes && obj.attributes.title) || JSON.stringify(obj);

ruleToc.chapterUrl:
@js:
let obj = JSON.parse(result);
let mid = java.get("mid");
// 注意这里改成了 v3，并兼容了 id 和 chapter_id 两种可能的键名
let cid = obj.id || obj.chapter_id; 
"https://api-get-v3.mgsearcher.com/api/chapter/getinfo?m=" + mid + "&c=" + cid;
